// goTestNameRegexp matches a path segment shaped like a Go test directory:
// a function name starting with Test followed by an upper-case letter and
// ending in digits (the numeric suffix that `t.TempDir()` appends). The
// testing package documents this convention in `(*T).TempDir`.
var goTestNameRegexp = regexp.MustCompile(`/Test[A-Z][A-Za-z0-9_]*\d+/`)

// testDirFilterOverride is a test-only escape hatch. When set, it fully
// overrides IsTestDirPath's default behavior so the handful of tests in this
// package that need to exercise migration/sweep semantics against Go test
// temp paths can opt out of the filter. Production code MUST NOT set it.
// Access is guarded because test functions (and their sub-tests) may read
// the variable concurrently.
var (
	testDirFilterOverride   func(path string) bool
	testDirFilterOverrideMu sync.RWMutex
)

// IsTestDirPath reports whether path looks like a Go test temp directory
// that leaked into the server's registered-project list. These entries are
// never a real user project — they come from tests that forgot to isolate
// XDG_DATA_HOME. The check is intentionally aggressive: any match here makes
// the entry ineligible for long-term retention.
//
// Polluted state files are the hidden amplifier behind ddx-9ce6842a (beads
// perf) and ddx-2ceb02fa (sessions feed) — both cross-project queries iterate
// every registered project, and thousands of phantom /tmp/TestXxx/001
// entries inflate those loops by orders of magnitude.
//
// The rules match the bead contract for ddx-15f7ee0b:
//   - path starts with /tmp/, /private/tmp/, or /var/folders/ (macOS temp root)
//   - path contains a /Test[A-Z]\w*\d+/ segment (Go test naming convention)
func IsTestDirPath(path string) bool {
	testDirFilterOverrideMu.RLock()
	override := testDirFilterOverride
	testDirFilterOverrideMu.RUnlock()
	if override != nil {
		return override(path)
	}
	if path == "" {
		return false
	}
	if strings.HasPrefix(path, "/tmp/") ||
		strings.HasPrefix(path, "/private/tmp/") ||
		strings.HasPrefix(path, "/var/folders/") {
		return true
	}
	// Normalise trailing/leading so the regex sees bounded segments.
	probe := path
	if !strings.HasPrefix(probe, "/") {
		probe = "/" + probe
	}
	if !strings.HasSuffix(probe, "/") {
		probe = probe + "/"
	}
	return goTestNameRegexp.MatchString(probe)
}

// NodeState holds persistent identity for this ddx-server instance.
type NodeState struct {
	Name      string    `json:"name"`
	ID        string    `json:"id"`
	StartedAt time.Time `json:"started_at"`
	LastSeen  time.Time `json:"last_seen"`
}

// ProjectEntry represents a ddx project registered with this server.
type ProjectEntry struct {
	ID           string     `json:"id"`
	Name         string     `json:"name"`
	Path         string     `json:"path"`
	GitRemote    string     `json:"git_remote,omitempty"`
	RegisteredAt time.Time  `json:"registered_at"`
	LastSeen     time.Time  `json:"last_seen"`
	Unreachable  bool       `json:"unreachable,omitempty"`
	TombstonedAt *time.Time `json:"tombstoned_at,omitempty"`
}

// ServerState is the full persistent state for a ddx-server node.
// Designed so multiple nodes can eventually forward state to a coordinator.
type ServerState struct {
	SchemaVersion string         `json:"schema_version"`
	Node          NodeState      `json:"node"`
	Projects      []ProjectEntry `json:"projects"`

	mu             sync.RWMutex              `json:"-"`
	dir            string                    `json:"-"`
	workingDir     string                    `json:"-"` // root working directory; set post-init by server
	coordinatorReg *coordinatorRegistry      `json:"-"` // set by Server after workers are created
	beadIndexMu    sync.RWMutex              `json:"-"`
	beadIndex      map[string]beadIndexEntry `json:"-"`
}

const stateSchemaVersion = "1"

// loadServerState reads state from dir/server-state.json, initialising a fresh state
// if the file does not exist. nodeName is the resolved hostname/configured name.
func loadServerState(dir, nodeName string) *ServerState {
	s := &ServerState{
		SchemaVersion: stateSchemaVersion,
		dir:           dir,
		Node: NodeState{
			Name:      nodeName,
			ID:        nodeID(nodeName),
			StartedAt: time.Now().UTC(),
			LastSeen:  time.Now().UTC(),
		},
	}

	data, err := os.ReadFile(filepath.Join(dir, "server-state.json"))
	if err != nil {
		return s // fresh state
	}
	var persisted ServerState
	if err := json.Unmarshal(data, &persisted); err != nil {
		return s // corrupt — start fresh
	}
	// Preserve projects and node ID from prior run; update runtime fields.
	s.Node.ID = persisted.Node.ID
	s.Projects = persisted.Projects

	// Migration: canonicalize paths, resolve linked worktrees, dedupe, sweep.
	phantoms := s.migrate()
	if phantoms > 0 {
		log.Printf("ddx-server: Pruned %d phantom test-dir projects from state file", phantoms)
	}
	return s
}

// migrate canonicalises all stored project paths, resolves linked-worktree
// paths to the primary worktree, deduplicates entries with the same canonical
// path, and marks entries whose paths no longer exist as unreachable. Entries
// that are unreachable and whose last_seen is older than 24 h are removed.
// Test-dir paths (matching IsTestDirPath) are dropped unconditionally — they
// are never real user projects, only pollution from tests that forgot to
// isolate XDG_DATA_HOME (ddx-15f7ee0b Fix B).
//
// Returns the number of entries dropped because they matched a test-dir
// pattern, so callers can log the cleanup on startup.
//
// This runs once on startup so a state file that accumulated thousands of
// phantom worktree paths is cleaned up automatically.
func (s *ServerState) migrate() int {
	now := time.Now().UTC()
	cutoff := now.Add(-24 * time.Hour)

	// Pass 1: canonicalize paths (symlinks + abs). We do NOT run git commands
	// here — linked-worktree resolution happens at RegisterProject time.
	// Keeping migration git-free makes it safe to run against state files that
	// contain thousands of temp-dir paths, many of which may exist on disk.
	for i := range s.Projects {
		canonical := canonicalizePath(s.Projects[i].Path)
		if canonical != "" {
			s.Projects[i].Path = canonical
			s.Projects[i].Name = filepath.Base(canonical)
			s.Projects[i].ID = projectID(canonical)
		}
	}

	// Pass 2: dedupe by canonical path — keep earliest RegisteredAt, latest LastSeen.
	seen := make(map[string]int) // path → index in deduped
	projects := make([]ProjectEntry, 0, len(s.Projects))
	for _, p := range s.Projects {
		if idx, ok := seen[p.Path]; ok {
			// Merge: keep earliest RegisteredAt, latest LastSeen.
			if p.RegisteredAt.Before(projects[idx].RegisteredAt) {
				projects[idx].RegisteredAt = p.RegisteredAt
			}
			if p.LastSeen.After(projects[idx].LastSeen) {
				projects[idx].LastSeen = p.LastSeen
			}
			// Keep non-empty git remote.
			if p.GitRemote != "" && projects[idx].GitRemote == "" {
				projects[idx].GitRemote = p.GitRemote
			}
		} else {
			seen[p.Path] = len(projects)
			projects = append(projects, p)
		}
	}

	// Pass 3: reachability + test-dir sweep.
	phantoms := 0
	kept := make([]ProjectEntry, 0, len(projects))
	for _, p := range projects {
		if IsTestDirPath(p.Path) {
			// Test-dir pollution is never a real user project. Drop whether or
			// not the path currently exists on disk — a transient temp dir
			// should never survive a restart.
			phantoms++
			continue
		}
		_, statErr := os.Stat(p.Path)
		if statErr == nil {
			// Path exists — clear any stale tombstone.
			p.Unreachable = false
			p.TombstonedAt = nil
			kept = append(kept, p)
			continue
		}
		// Path missing. Drop immediately if last seen > 24 h ago (old phantom).
		if p.LastSeen.Before(cutoff) {
			continue

package server

import (
	"errors"
	"mime"
	"os"
	"path/filepath"
	"sort"
	"strconv"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
)

// runBundleInlineMaxBytes is the per-file cap for inline content returned by
// runBundleFile. Files larger than this return truncated=true with no body so
// the client can fall back to a download path.
const runBundleInlineMaxBytes = 64 * 1024

// runBundleInlineExtensions is the set of file extensions and exact filenames
// whose contents may be inlined (when also under the size cap). Anything
// outside this set is download-only.
var runBundleInlineExtensions = map[string]bool{
	".txt":          true,
	".md":           true,
	"manifest.json": true,
	"prompt.md":     true,
	"result.json":   true,
}

// errRunBundleOutsideRoot is returned by resolveRunBundlePath when the
// requested path canonicalises outside the run's bundle root.
var errRunBundleOutsideRoot = errors.New("run bundle: path outside bundle root")

// runBundleRoot returns the canonical absolute filesystem path for the run's
// bundle directory, plus the project the run belongs to. The second return
// value is the project root; the third is true when a usable bundle exists.
func (s *ServerState) runBundleRoot(runID string) (bundleRoot, projectRoot string, ok bool) {
	if runID == "" {
		return "", "", false
	}
	for _, proj := range s.GetProjects(false) {
		bundleID := bundleIDForRunID(proj.Path, runID)
		if bundleID == "" {
			continue
		}
		root := filepath.Join(proj.Path, agent.ExecuteBeadArtifactDir, bundleID)
		info, err := os.Stat(root)
		if err != nil || !info.IsDir() {
			continue
		}
		// Canonicalize root so symlink-escape checks compare apples to apples.
		canonical, err := filepath.EvalSymlinks(root)
		if err != nil {
			canonical = root
		}
		return canonical, proj.Path, true
	}
	return "", "", false
}

// bundleIDForRunID maps a Run.id to its bundle directory name under
// .ddx/executions/, or "" when the run has no bundle.
//
// Three input shapes are recognized:
//   - "exec-<bundleID>"             → try-layer synthesised from bundle directory
//   - run-layer session ID with a BundlePath pointing under .ddx/executions/
//   - bundle ID directly (for caller convenience)
func bundleIDForRunID(projectRoot, runID string) string {
	if strings.HasPrefix(runID, "exec-") {
		return strings.TrimPrefix(runID, "exec-")
	}
	// Try resolving the run-layer session entry.
	logDir := agent.SessionLogDirForWorkDir(projectRoot)
	entry, ok, err := agent.FindSessionIndex(logDir, runID)
	if err == nil && ok && entry.BundlePath != "" {
		return bundleIDFromPath(entry.BundlePath)
	}
	return ""
}

// bundleIDFromPath extracts the bundle directory leaf name from a BundlePath
// of the form ".ddx/executions/<bundleID>" or ".ddx/executions/<bundleID>/...".
func bundleIDFromPath(p string) string {
	clean := filepath.ToSlash(p)
	prefix := filepath.ToSlash(agent.ExecuteBeadArtifactDir) + "/"
	idx := strings.Index(clean, prefix)
	if idx < 0 {
		return ""
	}
	rest := clean[idx+len(prefix):]
	if i := strings.Index(rest, "/"); i >= 0 {
		rest = rest[:i]
	}
	if !looksLikeBundleID(rest) {
		return ""
	}
	return rest
}

// resolveRunBundlePath canonicalises a user-supplied path (relative to the
// bundle root) and returns the absolute filesystem path inside the bundle.
// It rejects:
//   - absolute paths
//   - paths containing ".." that escape the root
//   - symlink targets that resolve outside the root
//
// All three rejection modes return errRunBundleOutsideRoot. The path argument
// must use forward slashes (or be normalisable to them).
func resolveRunBundlePath(bundleRoot, path string) (string, error) {
	if path == "" {
		return "", errRunBundleOutsideRoot
	}
	if filepath.IsAbs(path) || strings.HasPrefix(path, "/") {
		return "", errRunBundleOutsideRoot
	}
	clean := filepath.Clean(filepath.FromSlash(path))
	if clean == "." || clean == ".." || strings.HasPrefix(clean, ".."+string(filepath.Separator)) {
		return "", errRunBundleOutsideRoot
	}
	full := filepath.Join(bundleRoot, clean)
	// Re-clean and confirm it sits under bundleRoot.
	full = filepath.Clean(full)
	rel, err := filepath.Rel(bundleRoot, full)
	if err != nil || rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) {
		return "", errRunBundleOutsideRoot
	}
	// If the file (or any parent) is a symlink, confirm the eval'd target
	// also remains inside the canonical bundleRoot. Missing files are OK to
	// pass through here — the caller will return 404 when reading.
	if eval, err := filepath.EvalSymlinks(full); err == nil {
		evalClean := filepath.Clean(eval)
		rel2, err := filepath.Rel(bundleRoot, evalClean)
		if err != nil || rel2 == ".." || strings.HasPrefix(rel2, ".."+string(filepath.Separator)) {
			return "", errRunBundleOutsideRoot
		}
	}
	return full, nil
}

// listRunBundleFiles walks the bundle root and returns one RunBundleFile per
// regular file. Symlinks pointing outside the root are skipped.
func listRunBundleFiles(bundleRoot string) []*ddxgraphql.RunBundleFile {
	var out []*ddxgraphql.RunBundleFile
	if bundleRoot == "" {
		return out
	}
	_ = filepath.Walk(bundleRoot, func(p string, info os.FileInfo, err error) error {
		if err != nil || info == nil {
			return nil
		}
		if info.IsDir() {
			return nil
		}
		// Skip anything that, after symlink resolution, escapes the root.
		if eval, err := filepath.EvalSymlinks(p); err == nil {
			rel, err := filepath.Rel(bundleRoot, filepath.Clean(eval))
			if err != nil || rel == ".." || strings.HasPrefix(rel, ".."+string(filepath.Separator)) {
				return nil
			}
		}
		rel, err := filepath.Rel(bundleRoot, p)
		if err != nil {
			return nil
		}
		size := int(info.Size())
		mt := mimeTypeForPath(rel)
		out = append(out, &ddxgraphql.RunBundleFile{
			Path:     filepath.ToSlash(rel),
			Size:     size,
			MimeType: mt,
		})
		return nil
	})
	sort.Slice(out, func(i, j int) bool { return out[i].Path < out[j].Path })
	return out
}

// readRunBundleFile resolves path under bundleRoot and returns the file's
// inline content (when allowed) plus size/truncated metadata. The bool return
// is false when the file does not exist (404) or fails the confinement check.
func readRunBundleFile(bundleRoot, path string) (*ddxgraphql.RunBundleFileContent, bool) {
	full, err := resolveRunBundlePath(bundleRoot, path)
	if err != nil {
		return nil, false
	}
	info, err := os.Stat(full)
	if err != nil || info.IsDir() {
		return nil, false
	}
	size := int(info.Size())
	mt := mimeTypeForPath(path)
	out := &ddxgraphql.RunBundleFileContent{
		Path:      filepath.ToSlash(path),
		SizeBytes: size,
		Truncated: false,
		MimeType:  mt,
	}
	if !runBundleInlineAllowed(path) || size > runBundleInlineMaxBytes {
		out.Truncated = true
		return out, true
	}
	data, err := os.ReadFile(full)
	if err != nil {
		out.Truncated = true
		return out, true
	}
	body := string(data)
	out.Content = &body
	return out, true
}

// runBundleInlineAllowed reports whether a path qualifies for inline content
// based on extension and exact-filename whitelist rules from Story 16.
func runBundleInlineAllowed(path string) bool {
	base := strings.ToLower(filepath.Base(filepath.FromSlash(path)))
	if runBundleInlineExtensions[base] {
		return true
	}

package server

import (
	"os"
	"path/filepath"
	"runtime"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
)

// TestRunBundleFile_PathTraversalRejected covers AC: bundleFile rejects path
// traversal (`..`), absolute paths outside the bundle root, and symlink
// targets that escape the root.
func TestRunBundleFile_PathTraversalRejected(t *testing.T) {
	workDir, bundleID := setupRunBundleFixture(t)
	state := stateWithProject(workDir)

	cases := []struct {
		name string
		path string
	}{
		{"dotdot prefix", "../../etc/passwd"},
		{"dotdot mid", "subdir/../../escape.txt"},
		{"absolute path", "/etc/passwd"},
		{"absolute under workdir", filepath.Join(workDir, ".ddx", "config.yaml")},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			out, ok := state.GetRunBundleFileGraphQL("exec-"+bundleID, tc.path)
			if ok || out != nil {
				t.Fatalf("expected reject for %q, got ok=%v out=%+v", tc.path, ok, out)
			}
		})
	}
}

// TestRunBundleFile_SymlinkEscapeRejected creates a symlink inside the
// bundle that targets a file outside the root and confirms the resolver
// refuses to read it.
func TestRunBundleFile_SymlinkEscapeRejected(t *testing.T) {
	if runtime.GOOS == "windows" {
		t.Skip("symlinks not portable on windows test runners")
	}
	workDir, bundleID := setupRunBundleFixture(t)
	bundleRoot := filepath.Join(workDir, agent.ExecuteBeadArtifactDir, bundleID)
	outsideFile := filepath.Join(workDir, "outside-secret.txt")
	if err := os.WriteFile(outsideFile, []byte("secret"), 0o644); err != nil {
		t.Fatal(err)
	}
	if err := os.Symlink(outsideFile, filepath.Join(bundleRoot, "escape.txt")); err != nil {
		t.Fatal(err)
	}
	state := stateWithProject(workDir)
	out, ok := state.GetRunBundleFileGraphQL("exec-"+bundleID, "escape.txt")
	if ok || out != nil {
		t.Fatalf("expected symlink-escape rejection, got ok=%v out=%+v", ok, out)
	}
}

// TestRunBundleFile_SizeCap covers AC: files >64KB return truncated=true with
// sizeBytes populated and no inline content.
func TestRunBundleFile_SizeCap(t *testing.T) {
	workDir, bundleID := setupRunBundleFixture(t)
	bundleRoot := filepath.Join(workDir, agent.ExecuteBeadArtifactDir, bundleID)
	bigPath := filepath.Join(bundleRoot, "big.md")
	body := strings.Repeat("a", runBundleInlineMaxBytes+1)
	if err := os.WriteFile(bigPath, []byte(body), 0o644); err != nil {
		t.Fatal(err)
	}
	state := stateWithProject(workDir)
	out, ok := state.GetRunBundleFileGraphQL("exec-"+bundleID, "big.md")
	if !ok || out == nil {
		t.Fatal("expected file metadata, got nil")
	}
	if !out.Truncated {
		t.Fatal("expected truncated=true for >64KB file")
	}
	if out.Content != nil {
		t.Fatalf("expected no inline content for >64KB file, got %d bytes", len(*out.Content))
	}
	if out.SizeBytes != runBundleInlineMaxBytes+1 {
		t.Fatalf("expected sizeBytes=%d, got %d", runBundleInlineMaxBytes+1, out.SizeBytes)
	}
}

// TestRunBundleFile_WhitelistEnforcement covers AC: files outside the
// allowed-extension whitelist return truncated=true with no inline content,
// while small whitelisted files inline.
func TestRunBundleFile_WhitelistEnforcement(t *testing.T) {
	workDir, bundleID := setupRunBundleFixture(t)
	bundleRoot := filepath.Join(workDir, agent.ExecuteBeadArtifactDir, bundleID)

	// Whitelisted small file: should inline.
	allowed := filepath.Join(bundleRoot, "notes.md")
	if err := os.WriteFile(allowed, []byte("hello"), 0o644); err != nil {
		t.Fatal(err)
	}
	// Non-whitelisted small file: should be truncated=true.
	denied := filepath.Join(bundleRoot, "trace.bin")
	if err := os.WriteFile(denied, []byte("\x00\x01\x02"), 0o644); err != nil {
		t.Fatal(err)
	}

	state := stateWithProject(workDir)

	out, ok := state.GetRunBundleFileGraphQL("exec-"+bundleID, "notes.md")
	if !ok || out == nil {
		t.Fatal("expected whitelisted file to resolve")
	}
	if out.Truncated || out.Content == nil || *out.Content != "hello" {
		t.Fatalf("expected inline content for notes.md, got truncated=%v content=%v", out.Truncated, out.Content)
	}

	out, ok = state.GetRunBundleFileGraphQL("exec-"+bundleID, "trace.bin")
	if !ok || out == nil {
		t.Fatal("expected non-whitelisted file to resolve metadata")
	}
	if !out.Truncated || out.Content != nil {
		t.Fatalf("expected truncated=true with no content for trace.bin, got %+v", out)
	}
	if out.SizeBytes != 3 {
		t.Fatalf("expected sizeBytes=3, got %d", out.SizeBytes)
	}
}

// TestRunBundleFile_MissingPathReturns404 covers AC: missing files are 404.
func TestRunBundleFile_MissingPathReturns404(t *testing.T) {
	workDir, bundleID := setupRunBundleFixture(t)
	state := stateWithProject(workDir)
	out, ok := state.GetRunBundleFileGraphQL("exec-"+bundleID, "does-not-exist.md")
	if ok || out != nil {
		t.Fatalf("expected nil for missing file, got ok=%v out=%+v", ok, out)
	}
}

// TestRunBundleFiles_Listing confirms bundleFiles returns one entry per file
// with size + mimeType populated.
func TestRunBundleFiles_Listing(t *testing.T) {
	workDir, bundleID := setupRunBundleFixture(t)
	bundleRoot := filepath.Join(workDir, agent.ExecuteBeadArtifactDir, bundleID)
	if err := os.WriteFile(filepath.Join(bundleRoot, "extra.txt"), []byte("x"), 0o644); err != nil {
		t.Fatal(err)
	}
	files := listRunBundleFiles(bundleRoot)
	got := map[string]int{}
	for _, f := range files {
		got[f.Path] = f.Size
	}
	if got["manifest.json"] == 0 {
		t.Errorf("expected manifest.json in bundleFiles, got %v", got)
	}
	if got["result.json"] == 0 {
		t.Errorf("expected result.json in bundleFiles, got %v", got)
	}
	if got["extra.txt"] != 1 {
		t.Errorf("expected extra.txt size=1, got %v", got)
	}
	for _, f := range files {
		if f.MimeType == "" {
			t.Errorf("file %q has empty mimeType", f.Path)
		}
	}
}

// TestRunToolCalls_PersistedAtDrain covers AC: tool calls are read from the
// persisted SessionIndexEntry.ToolCalls field, NOT parsed from log files at
// resolver time. We write a session row directly and confirm the resolver
// returns its ToolCalls without scanning any log file.
func TestRunToolCalls_PersistedAtDrain(t *testing.T) {
	workDir := t.TempDir()
	writeConfig(t, workDir, `version: "1.0"`+"\n")
	state := stateWithProject(workDir)

	now := time.Date(2026, 5, 1, 0, 0, 0, 0, time.UTC)
	entry := agent.SessionIndexEntry{
		ID:          "sess-tools-001",
		Harness:     "claude",
		BillingMode: "paid",
		StartedAt:   now,
		ToolCalls: []agent.ToolCallEntry{
			{Tool: "Read", Input: `{"path":"a"}`, Output: "ok", Duration: 12},
			{Tool: "Bash", Input: `{"cmd":"ls"}`, Error: "exit 1"},
		},
	}
	if err := agent.AppendSessionIndex(agent.SessionLogDirForWorkDir(workDir), entry, now); err != nil {
		t.Fatal(err)
	}

	calls := state.GetRunToolCallsGraphQL("sess-tools-001")
	if len(calls) != 2 {
		t.Fatalf("expected 2 tool calls, got %d", len(calls))
	}
	if calls[0].Tool != "Read" || calls[0].Seq != 0 {
		t.Errorf("call[0]=%+v want Tool=Read Seq=0", calls[0])
	}
	if calls[0].DurationMs == nil || *calls[0].DurationMs != 12 {
		t.Errorf("call[0] DurationMs=%v want 12", calls[0].DurationMs)
	}
	if calls[1].Error == nil || *calls[1].Error != "exit 1" {
		t.Errorf("call[1] Error=%v want 'exit 1'", calls[1].Error)
	}
}

// TestSessionIndexEntryFromResult_PersistsToolCalls confirms the drain-time
// pipeline (Result.ToolCalls → SessionIndexEntry.ToolCalls) is wired up.
func TestSessionIndexEntryFromResult_PersistsToolCalls(t *testing.T) {
	calls := []agent.ToolCallEntry{
		{Tool: "Read", Input: `{}`},
		{Tool: "Edit", Input: `{}`, Output: "ok"},
	}
	result := &agent.Result{Harness: "claude", ToolCalls: calls}
	now := time.Now().UTC()
