		NativeSessionID: nativeSessionID,
		TraceID:         traceID,
		SpanID:          spanID,
		BundlePath:      filepath.ToSlash(bundlePath),
		NativeLogRef:    filepath.ToSlash(nativeLogRef),
		Effort:          inputs.Effort,
		Detail:          result.Error,
