 15	// Story 16 review-session contract:
 16	//
 17	// Every review session lives under .ddx/reviews/<session-id>/ and consists of:
 18	//   - manifest.json: the session metadata written at creation time. This file
 19	//     is the durable identity/status/cost record for the session.
 20	//   - turns.jsonl: append-only JSONL containing one review turn per line. Each
 21	//     record stores the actor, content, cost_usd, and created_at fields.
 22	//   - attachments/: binary payloads attached to turns or session evidence.
 23	//
 24	// Writers must create manifest.json before appending any turns. Readers should
 25	// treat turns.jsonl as append-only and ignore trailing newlines or an empty file.
 26	
 27	const (
 28		reviewSessionsDirName = "reviews"
 29		reviewManifestName    = "manifest.json"
 30		reviewTurnsName       = "turns.jsonl"
 31		reviewAttachmentsDir  = "attachments"
 32	)
 33	
 34	// ReviewSession captures the durable server-side schema for a review session.
 35	// The in-memory session may accumulate Turns as they are appended, while the
 36	// on-disk manifest only stores the metadata fields.
 37	type ReviewSession struct {
 38		ID             string       `json:"id"`
 39		ArtifactID     string       `json:"artifact_id"`
 40		ArtifactSHA    string       `json:"artifact_sha"`
 41		ArtifactGitRev string       `json:"artifact_git_rev"`
 42		SystemRubric   string       `json:"system_rubric"`
 43		TemplateRef    string       `json:"template_ref"`
 44		PromptRef      string       `json:"prompt_ref"`
 45		Status         string       `json:"status"`
 46		Turns          []ReviewTurn `json:"turns,omitempty"`
 47		CostUSD        float64      `json:"cost_usd"`
 48		MaxBillableUSD float64      `json:"max_billable_usd"`
 49	}
 50	
 51	// ReviewTurn is the append-only on-disk record for one review-model turn.
 52	type ReviewTurn struct {
 53		Actor     string    `json:"actor"`
 54		Content   string    `json:"content"`
 55		CostUSD   float64   `json:"cost_usd"`
 56		CreatedAt time.Time `json:"created_at"`
 57	}
 58	
 59	type reviewSessionManifest struct {
 60		ID             string  `json:"id"`
 61		ArtifactID     string  `json:"artifact_id"`
 62		ArtifactSHA    string  `json:"artifact_sha"`
 63		ArtifactGitRev string  `json:"artifact_git_rev"`
 64		SystemRubric   string  `json:"system_rubric"`
 65		TemplateRef    string  `json:"template_ref"`
 66		PromptRef      string  `json:"prompt_ref"`
 67		Status         string  `json:"status"`
 68		CostUSD        float64 `json:"cost_usd"`
 69		MaxBillableUSD float64 `json:"max_billable_usd"`
 70	}
