 72	// ReviewSessionStore manages review-session persistence under one project root.
 73	type ReviewSessionStore struct {
 74		projectRoot string
 75		mu          sync.Mutex
 76	}
 77	
 78	// NewReviewSessionStore returns a store rooted at projectRoot.
 79	func NewReviewSessionStore(projectRoot string) *ReviewSessionStore {
 80		return &ReviewSessionStore{projectRoot: projectRoot}
 81	}
 82	
 83	// Create persists the review-session manifest and initializes the review
 84	// session directory layout.
 85	func (s *ReviewSessionStore) Create(session ReviewSession) error {
 86		if s == nil {
 87			return errors.New("review session store: nil store")
 88		}
 89		root, err := s.sessionRoot(session.ID)
 90		if err != nil {
 91			return err
 92		}
 93	
 94		s.mu.Lock()
 95		defer s.mu.Unlock()
 96	
 97		if err := os.MkdirAll(filepath.Join(root, reviewAttachmentsDir), 0o755); err != nil {
 98			return fmt.Errorf("review session: mkdir attachments: %w", err)
 99		}
100		if err := writeJSONFile(filepath.Join(root, reviewManifestName), reviewSessionManifestFrom(session)); err != nil {
101			return err
102		}
103		if err := os.WriteFile(filepath.Join(root, reviewTurnsName), nil, 0o644); err != nil {
104			return fmt.Errorf("review session: seed turns: %w", err)
105		}
106		return nil
107	}
108	
109	// AppendTurn appends a single turn to turns.jsonl for sessionID.
110	func (s *ReviewSessionStore) AppendTurn(sessionID string, turn ReviewTurn) error {
111		if s == nil {
112			return errors.New("review session store: nil store")
113		}
114		root, err := s.sessionRoot(sessionID)
115		if err != nil {
116			return err
117		}
118	
119		s.mu.Lock()
120		defer s.mu.Unlock()
121	
122		if err := os.MkdirAll(root, 0o755); err != nil {
123			return fmt.Errorf("review session: mkdir session: %w", err)
124		}
125		if turn.CreatedAt.IsZero() {
126			turn.CreatedAt = time.Now().UTC()
127		}
128		path := filepath.Join(root, reviewTurnsName)
129		f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
130		if err != nil {
131			return fmt.Errorf("review session: open turns: %w", err)
132		}
133		defer f.Close()
134		if err := json.NewEncoder(f).Encode(turn); err != nil {
135			return fmt.Errorf("review session: encode turn: %w", err)
136		}
137		return nil
138	}
