140	// Load reads a review session from disk, merging the manifest metadata and the
141	// turn stream into one in-memory ReviewSession value.
142	func (s *ReviewSessionStore) Load(sessionID string) (*ReviewSession, error) {
143		if s == nil {
144			return nil, errors.New("review session store: nil store")
145		}
146		root, err := s.sessionRoot(sessionID)
147		if err != nil {
148			return nil, err
149		}
150	
151		data, err := os.ReadFile(filepath.Join(root, reviewManifestName))
152		if err != nil {
153			return nil, fmt.Errorf("review session: read manifest: %w", err)
154		}
155		var manifest reviewSessionManifest
156		if err := json.Unmarshal(data, &manifest); err != nil {
157			return nil, fmt.Errorf("review session: parse manifest: %w", err)
158		}
159		session := &ReviewSession{
160			ID:             manifest.ID,
161			ArtifactID:     manifest.ArtifactID,
162			ArtifactSHA:    manifest.ArtifactSHA,
163			ArtifactGitRev: manifest.ArtifactGitRev,
164			SystemRubric:   manifest.SystemRubric,
165			TemplateRef:    manifest.TemplateRef,
166			PromptRef:      manifest.PromptRef,
167			Status:         manifest.Status,
168			CostUSD:        manifest.CostUSD,
169			MaxBillableUSD: manifest.MaxBillableUSD,
170		}
171	
172		turnsPath := filepath.Join(root, reviewTurnsName)
173		f, err := os.Open(turnsPath)
174		if err != nil {
175			if os.IsNotExist(err) {
176				return session, nil
177			}
178			return nil, fmt.Errorf("review session: read turns: %w", err)
179		}
180		defer f.Close()
181	
182		scanner := bufio.NewScanner(f)
183		scanner.Buffer(make([]byte, 0, 64*1024), 8*1024*1024)
184		for scanner.Scan() {
185			line := strings.TrimSpace(scanner.Text())
186			if line == "" {
187				continue
188			}
189			var turn ReviewTurn
190			if err := json.Unmarshal([]byte(line), &turn); err != nil {
191				return nil, fmt.Errorf("review session: parse turn: %w", err)
192			}
193			session.Turns = append(session.Turns, turn)
194		}
195		if err := scanner.Err(); err != nil {
196			return nil, fmt.Errorf("review session: scan turns: %w", err)
197		}
198		return session, nil
199	}
