201	func (s *ReviewSessionStore) sessionRoot(sessionID string) (string, error) {
202		if s == nil {
203			return "", errors.New("review session store: nil store")
204		}
205		if s.projectRoot == "" {
206			return "", errors.New("review session store: empty project root")
207		}
208		if sessionID == "" {
209			return "", errors.New("review session store: empty session id")
210		}
211		if sessionID == "." || sessionID == ".." || strings.ContainsAny(sessionID, "/\\") {
212			return "", fmt.Errorf("review session store: invalid session id %q", sessionID)
213		}
214		root := filepath.Join(s.projectRoot, ".ddx", reviewSessionsDirName, sessionID)
215		return root, nil
