233	func writeJSONFile(path string, v any) error {
234		data, err := json.MarshalIndent(v, "", "  ")
235		if err != nil {
236			return fmt.Errorf("review session: marshal %s: %w", path, err)
237		}
238		data = append(data, '\n')
239		if err := os.WriteFile(path, data, 0o644); err != nil {
240			return fmt.Errorf("review session: write %s: %w", path, err)
241		}
242		return nil
243	}
